## 작업 2: MainLayout.jsx 전면 재작성

파일: `D:\20. POC\TrmWordDict\frontend\src\layouts\MainLayout.jsx`

Read 후 전체 내용을 아래로 교체(Write):

```jsx
import { Ban, BookOpen, Database, FolderTree, Home, LogOut } from 'lucide-react';
import { NavLink, Outlet, useNavigate } from 'react-router-dom';
import { logout as logoutApi } from '@/features/auth/authApi';
import { Button } from '@/shared/components/ui/button';
import { ThemeToggle } from '@/shared/components/ThemeToggle/ThemeToggle';
import { useAuthStore } from '@/store/useAuthStore';
import { MENU_ITEMS } from './menuItems';

const iconMap = {
    home: Home,
    upload: Database,
    category: FolderTree,
    word: BookOpen,
    forbidden: Ban,
};

const NAV_GROUPS = [
    { label: '관리', key: 'manage' },
    { label: '가져오기', key: 'import' },
];

export const MainLayout = () => {
    const navigate = useNavigate();
    const user = useAuthStore((state) => state.user);
    const logout = useAuthStore((state) => state.logout);

    const handleLogout = async () => {
        try {
            await logoutApi();
        } finally {
            logout();
            navigate('/login');
        }
    };

    return (
        <div className='flex min-h-screen bg-slate-50 dark:bg-slate-900'>
            {/* Sidebar */}
            <aside className='hidden w-64 flex-shrink-0 flex-col border-r border-slate-200 bg-white dark:border-slate-800 dark:bg-slate-950 lg:flex'>
                {/* Brand */}
                <div className='flex h-14 items-center gap-3 border-b border-slate-200 px-4 dark:border-slate-800'>
                    <div className='flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-lg bg-gradient-to-br from-blue-600 to-blue-400 text-sm font-bold text-white shadow-sm'>
                        T
                    </div>
                    <span className='text-sm font-semibold text-slate-900 dark:text-slate-100'>TrmWordDict</span>
                </div>

                {/* Nav */}
                <nav className='flex-1 space-y-4 overflow-y-auto px-3 py-4'>
                    {NAV_GROUPS.map((group) => {
                        const items = MENU_ITEMS.filter(
                            (item) =>
                                item.group === group.key &&
                                (!item.requiredRole || item.requiredRole === user?.role),
                        );
                        if (items.length === 0) return null;
                        return (
                            <div key={group.key}>
                                <p className='mb-1.5 px-2 text-[11px] font-medium uppercase tracking-wider text-slate-400 dark:text-slate-500'>
                                    {group.label}
                                </p>
                                <div className='space-y-0.5'>
                                    {items.map((item) => {
                                        const Icon = iconMap[item.icon] ?? FolderTree;
                                        return (
                                            <NavLink
                                                key={item.route}
                                                to={item.route}
                                                className={({ isActive }) =>
                                                    `flex items-center gap-3 rounded-lg px-3 py-2 text-sm transition-colors ${
                                                        isActive
                                                            ? 'bg-slate-100 font-medium text-slate-900 dark:bg-slate-800 dark:text-slate-100'
                                                            : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900 dark:text-slate-400 dark:hover:bg-slate-800/60 dark:hover:text-slate-100'
                                                    }`
                                                }
                                            >
                                                <Icon className='h-4 w-4 shrink-0' />
                                                <span>{item.label}</span>
                                            </NavLink>
                                        );
                                    })}
                                </div>
                            </div>
                        );
                    })}
                </nav>

                {/* User Footer */}
                <div className='border-t border-slate-200 p-3 dark:border-slate-800'>
                    <div className='flex items-center gap-3 rounded-lg px-2 py-2'>
                        <div className='flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full bg-slate-200 text-xs font-semibold text-slate-700 dark:bg-slate-700 dark:text-slate-300'>
                            {user?.name?.charAt(0) ?? 'U'}
                        </div>
                        <div className='min-w-0 flex-1'>
                            <p className='truncate text-sm font-medium text-slate-900 dark:text-slate-100'>
                                {user?.name}
                            </p>
                            <p className='truncate text-xs text-slate-500 dark:text-slate-400'>{user?.role}</p>
                        </div>
                    </div>
                </div>
            </aside>

            {/* Main area */}
            <div className='flex min-w-0 flex-1 flex-col'>
                {/* Topbar */}
                <header className='flex h-14 flex-shrink-0 items-center justify-between border-b border-slate-200 bg-white px-6 dark:border-slate-800 dark:bg-slate-950'>
                    <span className='text-sm font-medium text-slate-500 dark:text-slate-400'>
                        행정 표준 용어 사전
                    </span>
                    <div className='flex items-center gap-1'>
                        <ThemeToggle />
                        <Button
                            variant='ghost'
                            size='sm'
                            className='gap-2 text-slate-600 dark:text-slate-400'
                            onClick={handleLogout}
                        >
                            <LogOut className='h-4 w-4' />
                            <span className='hidden sm:inline'>로그아웃</span>
                        </Button>
                    </div>
                </header>

                {/* Page content */}
                <main className='flex-1 p-6'>
                    <Outlet />
                </main>
            </div>
        </div>
    );
};
```

